CREATE TABLE "people" (
    "id" INTEGER PRIMARY KEY GENERATED ALWAYS AS IDENTITY,

    "name" VARCHAR NOT NULL,
    "phone" VARCHAR NOT NULL,
    "address" VARCHAR NOT NULL,
    "gender" VARCHAR,
    "birthdate" DATE
);

