CREATE TABLE "patrons" (
    "id" INTEGER PRIMARY KEY GENERATED ALWAYS AS IDENTITY,

    "id_person" INTEGER UNIQUE REFERENCES "people"("id")
);

CREATE TABLE "bookkeepers" (
    "id" INTEGER PRIMARY KEY GENERATED ALWAYS AS IDENTITY,

    "id_person" INTEGER UNIQUE REFERENCES "people"("id")
);

INSERT INTO "patrons" ("id_person")
