CREATE TABLE "shifts" (
    "id" INTEGER PRIMARY KEY GENERATED ALWAYS AS IDENTITY,

    "id_bookkeper" INTEGER REFERENCES "bookkeepers"("id"),

    "shift_date" DATE NOT NULL,
    "start_time" TIME NOT NULL,
    "end_time" TIME NOT NULL
);

